class Solution {
    public int maximumXOR(int[] nums) {
        int max = 0;
        for (int num : nums) {
            max = Math.max(max, num);
        }
        int maxBits = 0;
        while ((1 << maxBits) <= max) {
            maxBits++;
        }
        int[][] dp = new int[maxBits][maxBits];
        for (int num : nums) {
            int bits = Integer.toBinaryString(num).length();
            for (int i = 0; i < maxBits; i++) {
                if ((num & (1 << i)) != 0) {
                    dp[i][bits - 1]++;
                }
            }
        }
        int maxXOR = 0;
        for (int i = 0; i < maxBits; i++) {
            for (int j = 0; j < maxBits; j++) {
                if (i != j) {
                    maxXOR = Math.max(maxXOR, dp[i][j] + dp[j][i]);
                }
            }
        }
        return maxXOR;
    }
}
